/**
 * SmartMind Prefetch — instant.page-style link prefetching for Moodle.
 *
 * Hand-built AMD wrapper of amd/src/prefetch.js. Re-generate manually
 * when the source changes.
 *
 * @module theme_smartmind/prefetch
 */
define([], function() {

    var HOVER_DELAY_MS = 65;

    // URLs we must NOT prefetch. State-bound or side-effecting.
    var SKIP_PATTERNS = [
        /\/blocks\/iomad/,
        /\/local\/iomad/,
        /\/local\/sm_graphics_plugin\/pages\/iomad/,
        /\/login\//,
        /\/logout\.php/,
        /\/admin\//,
        /[?&]sesskey=/,
        /[?&]edit=1/
    ];

    var prefetched = new Set();
    var hoverTimer = null;

    function prefetch(url) {
        if (prefetched.has(url)) {
            return;
        }
        prefetched.add(url);
        var link = document.createElement('link');
        link.rel = 'prefetch';
        link.href = url;
        link.setAttribute('data-sm-prefetch', '');
        document.head.appendChild(link);
    }

    function shouldPrefetch(anchor) {
        if (!anchor || !anchor.href) {
            return false;
        }
        if (anchor.origin !== location.origin) {
            return false;
        }
        if (anchor.hasAttribute('download') || anchor.target === '_blank') {
            return false;
        }
        if (anchor.pathname === location.pathname && anchor.search === location.search) {
            return false;
        }
        if (/\.(zip|pdf|exe|dmg|tar|gz)$/i.test(anchor.pathname)) {
            return false;
        }
        var fullPath = anchor.pathname + anchor.search;
        for (var i = 0; i < SKIP_PATTERNS.length; i++) {
            if (SKIP_PATTERNS[i].test(fullPath)) {
                return false;
            }
        }
        return true;
    }

    function init() {
        if (window.__smPrefetchInitialized) {
            return;
        }
        window.__smPrefetchInitialized = true;

        document.addEventListener('mouseover', function(e) {
            var anchor = e.target.closest && e.target.closest('a[href]');
            if (!shouldPrefetch(anchor)) {
                return;
            }
            clearTimeout(hoverTimer);
            hoverTimer = setTimeout(function() {
                prefetch(anchor.href);
            }, HOVER_DELAY_MS);
        });

        document.addEventListener('mouseout', function(e) {
            if (e.target.closest && e.target.closest('a[href]')) {
                clearTimeout(hoverTimer);
            }
        });

        document.addEventListener('mousedown', function(e) {
            var anchor = e.target.closest && e.target.closest('a[href]');
            if (shouldPrefetch(anchor)) {
                prefetch(anchor.href);
            }
        }, true);

        document.addEventListener('touchstart', function(e) {
            var anchor = e.target.closest && e.target.closest('a[href]');
            if (shouldPrefetch(anchor)) {
                prefetch(anchor.href);
            }
        }, {capture: true, passive: true});
    }

    return {init: init};
});
